  "risk_assessment": {
    "overall_risk_level": "medium",
    "yellow_flags": [
      {
        "category": "Termination",
        "issue": "Ambiguous termination notice period ('reasonable notice' undefined)",
        "recommendation": "Negotiate explicit notice period (60 days is standard)"
      }
    ]
  },
  "human_review_required": {
    "required": true,
    "reasons": ["Ambiguous termination notice language"],
    "specific_questions": [
      "What notice period is acceptable for our business needs?",
      "Should we request explicit 60-day notice requirement?",
      "Is 30 days sufficient given our dependencies on this vendor?"
    ],
    "priority": "normal",
    "ambiguous_clauses": [
      {
        "clause": "Termination for convenience with 'reasonable notice'",
        "why_ambiguous": "Term 'reasonable' is subjective and not defined in contract",
        "possible_interpretations": [
          "10-15 days (vendor's likely interpretation)",
          "60 days (standard market practice)",
          "90 days (conservative interpretation)"
        ],
        "recommendation": "Replace 'reasonable notice' with explicit '60 days written notice'"
      }
    ]
  }
}

